import React, { useState } from "react";
import { MapContainer, TileLayer, LayersControl } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import PinsLayer from "./PinsLayer";
import { PIN_TYPES } from "./pinsConfig";

export default function Radar({ city = "Atlanta, US", pins = [], onAddPin }) {
  const CITY_CENTER = {
    "Atlanta, US": [33.749, -84.388],
    "New York, US": [40.7128, -74.006],
    "London, UK": [51.5074, -0.1278],
    "Dubai, AE": [25.2048, 55.2708],
  };

  const center = CITY_CENTER[city] ?? CITY_CENTER["Atlanta, US"];
  const [opacity, setOpacity] = useState(0.8);

  return (
    <div className="relative w-full h-[60vh] sm:h-[65vh] rounded-2xl overflow-hidden shadow-lg bg-black/50 backdrop-blur-md border border-white/10">
      <MapContainer
        center={center}
        zoom={8}
        scrollWheelZoom={false}
        className="w-full h-full"
      >
        <LayersControl position="topright">
          {/* Base Map */}
          <LayersControl.BaseLayer checked name="Base Map">
            <TileLayer
              url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              attribution='&copy; OpenStreetMap contributors'
            />
          </LayersControl.BaseLayer>

          {/* Precipitation Layer */}
          <LayersControl.Overlay checked name="Precipitation">
  <TileLayer
    url="https://tilecache.rainviewer.com/v2/radar/now/256/{z}/{x}/{y}/2/1_1.png"
    opacity={opacity}
    attribution="&copy; RainViewer"
  />
</LayersControl.Overlay>

          {/* Pins */}
          <LayersControl.Overlay name="Community Pins">
            <PinsLayer pins={pins} />
          </LayersControl.Overlay>
        </LayersControl>
      </MapContainer>
    </div>
  );
}
